-- Alex_C.T Media Server modular Profilarr v2 PCD operations.
-- 04: Resolution, source, edition, and release-fix regular expressions.
-- Requires 01.Core-Tags-Languages-Qualities.sql.

INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('Source: Block Remux-Raw Disk', '(?i)\b(?:remux|bdremux|blu[ ._-]?ray[ ._-]?remux|br[ ._-]?disk|bd[ ._-]?disk|bdrip[ ._-]?remux|raw[ ._-]?hd)\b', 'Optional strict detector for remux, BD remux, BR-DISK, BD-DISK, and raw HD style releases. The default additive profiles leave it unused so strong encodes can compete on merit without hard guards.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('Source: Block Remux-Raw Disk', 'Blocking');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('4K Gate: Block Missing HDR', '(?i)^(?=.*\b(?:2160p|4k)\b)(?!.*(?:\bhdr\b|\bhdr10\b|\bhdr10plus\b|\bhdr10\+|\bdovi\b|\bdv\b|dolby[ ._-]?vision|\b(?:10[ ._-]?bit|10b|main[ ._-]?10|yuv420p10le)\b)).*$', 'Optional strict detector for 2160p/4K releases that advertise neither HDR/Dolby Vision nor explicit 10-bit/Main 10. It preserves HDR-first behavior only when a stricter profile chooses to attach it.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('4K Gate: Block Missing HDR', 'HDR / 4K');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('4K Gate: Block Missing HDR', 'Blocking');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('1080p: UHD BluRay Source Bonus', '(?i)^(?=.*\b1080p\b)(?=.*\b(?:uhd[ ._-]?blu[ ._-]?ray|uhd[ ._-]?bluray)\b)(?!.*\b(?:2160p|4k)\b).*$', 'Small positive score for 1080p encodes sourced from UHD BluRay. This replaces the old accidental 4K bonus on 1080p UHD-source releases, so they get credit for the cleaner source without being treated as true 4K.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('1080p: UHD BluRay Source Bonus', 'Scoring');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('1080p: BluRay Preferred', '(?i)^(?=.*\b1080p\b)(?!.*\b(?:2160p|4k)\b)(?=.*\b(?:blu[ ._-]?ray|bluray)\b).*$', '1080p-only source bonus for BluRay releases. This keeps 1080p BluRay preference separate from the true 4K UHD BluRay preference.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('1080p: BluRay Preferred', 'Scoring');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('1080p: WEB-DL Preferred', '(?i)^(?=.*\b1080p\b)(?!.*\b(?:2160p|4k)\b)(?=.*\b(?:web[ ._-]?dl|webdl)\b).*$', '1080p-only source bonus for WEB-DL releases. It helps rank clean 1080p WEB-DL fallbacks without applying any 4K-specific logic.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('1080p: WEB-DL Preferred', 'Scoring');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('1080p: WEBRip Source', '(?i)^(?=.*\b1080p\b)(?!.*\b(?:2160p|4k)\b)(?=.*\b(?:web[ ._-]?rip|webrip)\b).*$', '1080p-only WEBRip source detector. Strict movie profiles can penalize or block it, while relaxed catalog and series profiles can keep it as a weaker fallback without borrowing generic or 4K source formats.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('1080p: WEBRip Source', 'Media Server');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('1080p: BDRip Source', '(?i)^(?=.*\b1080p\b)(?!.*\b(?:2160p|4k)\b)(?=.*\b(?:bd[ ._-]?rip|bdrip)\b).*$', '1080p-only BDRip source detector. It keeps 1080p BDRip handling separate from true BluRay and from 4K source rules.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('1080p: BDRip Source', 'Media Server');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('720p: BluRay Preferred', '(?i)^(?=.*\b720p\b)(?!.*\b(?:1080p|2160p|4k)\b)(?=.*\b(?:blu[ ._-]?ray|bluray)\b).*$', '720p-only BluRay source bonus. Keeps 720p BluRay ranking separate from 1080p and 4K BluRay rules.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('720p: BluRay Preferred', 'Scoring');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('720p: WEB-DL Preferred', '(?i)^(?=.*\b720p\b)(?!.*\b(?:1080p|2160p|4k)\b)(?=.*\b(?:web[ ._-]?dl|webdl)\b).*$', '720p-only WEB-DL source bonus for clean lower-resolution fallbacks.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('720p: WEB-DL Preferred', 'Scoring');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('720p: WEBRip Source', '(?i)^(?=.*\b720p\b)(?!.*\b(?:1080p|2160p|4k)\b)(?=.*\b(?:web[ ._-]?rip|webrip)\b).*$', '720p-only WEBRip source detector for relaxed catalog fallbacks. It does not apply to 1080p or 4K titles.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('720p: WEBRip Source', 'Media Server');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('720p: BDRip Source', '(?i)^(?=.*\b720p\b)(?!.*\b(?:1080p|2160p|4k)\b)(?=.*\b(?:bd[ ._-]?rip|bdrip)\b).*$', '720p-only BDRip source detector for older or hard-to-find catalog releases.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('720p: BDRip Source', 'Media Server');
