INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('4K: Block x264-H264', '(?i)^(?=.*\b(?:2160p|4k)\b)(?=.*\b(?:avc|[xh][ ._-]?264)\b).*$', 'Optional strict detector for 4K or 2160p releases encoded as x264, H.264, or AVC. The default additive profiles leave it unattached and instead let HEVC, AV1, or VVC win through positive bonuses.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('4K: Block x264-H264', 'HDR / 4K');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('4K: Block x264-H264', 'Blocking');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('4K: UHD BluRay Preferred', '(?i)^(?=.*\b(?:2160p|4k)\b)(?=.*\b(?:uhd[ ._-]?blu[ ._-]?ray|uhd[ ._-]?bluray|blu[ ._-]?ray|bluray)\b).*$', 'Rewards 4K UHD BluRay or 4K BluRay source tags. Used to prefer cleaner 4K disc-sourced encodes when the file still fits the space-balanced rules.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('4K: UHD BluRay Preferred', 'HDR / 4K');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('4K: UHD BluRay Preferred', 'Scoring');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('4K: WEB-DL Preferred', '(?i)^(?=.*\b(?:2160p|4k)\b)(?=.*\b(?:web[ ._-]?dl|webdl)\b).*$', 'Rewards 4K WEB-DL source tags. Useful for compact, clean 2160p HDR releases that are often smaller than BluRay-derived encodes.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('4K: WEB-DL Preferred', 'HDR / 4K');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('4K: WEB-DL Preferred', 'Scoring');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('Movie Source: Block WEBRip', '(?i)\b(?:web[ ._-]?rip|webrip)\b', 'Legacy generic WEBRip detector kept for cleanup and optional stricter profiles. Current curated profiles use resolution-specific WEBRip source formats instead, so 1080p/720p/576p/480p/4K handling stays separate.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('Movie Source: Block WEBRip', 'Blocking');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('Movie Source: Block WEBRip', 'Movies');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('Movie Source: Block BDRip', '(?i)\b(?:bd[ ._-]?rip|bdrip)\b', 'Legacy generic BDRip detector kept for cleanup and optional stricter profiles. Current curated profiles use resolution-specific BDRip source formats instead, so BDRip scoring can be strict for smart profiles and relaxed for catalog profiles.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('Movie Source: Block BDRip', 'Blocking');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('Movie Source: Block BDRip', 'Movies');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('4K Source: Block WEBRip', '(?i)^(?=.*\b(?:2160p|4k)\b)(?=.*\b(?:web[ ._-]?rip|webrip)\b).*$', 'Optional strict detector for 4K WEBRip releases. A stricter 4K lane can still reserve space for cleaner WEB-DL or UHD BluRay style sources.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('4K Source: Block WEBRip', 'HDR / 4K');
