INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('4K Audio: Block AAC-Only', '(?i)^(?=.*\b(?:2160p|4k)\b)(?=.*\baac\b).*$', 'Optional strict detector for 4K releases that only advertise AAC audio. It is available when you want the 4K lane to require stronger surround-friendly audio such as EAC3, AC3, DDP, or Atmos.');
